#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
//#define int long long
using namespace std;
const int N=1e6+10,Mod=19940417,INF=0x3f3f3f3f,M2=9970209,M6=3323403;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
inline int qpow(int x,long long k)
	{int res=1;while(k){if(k&1)res=1ll*res*x%Mod;x=1ll*x*x%Mod;k=k>>1;}return res;}
inline int Sum(int n,int mx)
{
	int ans=0;for(int l=1,r=0;l<=mx;l=r+1)
		{r=min(n/(n/l),mx);ans=(ans+1ll*(r-l+1)*(l+r)%Mod*M2%Mod*(n/l)%Mod)%Mod;}return ans;
}
int Mul(int n){return 1ll*n*(n+1)%Mod*(n+n+1)%Mod*M6%Mod;}
int main()
{
	int n=read(),m=read();if(n>m)swap(n,m);int ans=1ll*(1ll*n*n%Mod-Sum(n,n)%Mod+Mod)%Mod*(1ll*m*m%Mod-Sum(m,m)%Mod+Mod)%Mod;
	ans=(ans+1ll*n*Sum(m,n)%Mod+1ll*m*Sum(n,n)%Mod)%Mod;ans=(ans-1ll*n*n%Mod*m%Mod+Mod)%Mod;
	for(int l=1,r=0;l<=n;l=r+1){r=min(n/(n/l),m/(m/l));ans=(ans-1ll*(n/l)*(m/l)%Mod*(Mul(r)-Mul(l-1))%Mod+Mod)%Mod;}printf("%d\n",ans);
}
